            for (let y = centerY + 50; y &gt; centerY - 10; y -= 15) {
                ctx.beginPath();
                ctx.moveTo(centerX - 75, y);
                ctx.lineTo(centerX + 75, y);
                ctx.stroke();
            }
            
            // 垂直线条
            for (let x = centerX - 70; x &lt; centerX + 70; x += 20) {
                ctx.beginPath();
                ctx.moveTo(x, centerY + 55);
                ctx.lineTo(x - 10, centerY - 15);
